import os
from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# --- Database Configuration ---
# It's recommended to use environment variables for sensitive data
DB_HOST = os.environ.get('DB_HOST', 'localhost')
DB_NAME = os.environ.get('DB_NAME', 'your_database')
DB_USER = os.environ.get('DB_USER', 'your_user')
DB_PASSWORD = os.environ.get('DB_PASSWORD', 'your_password')
DB_PORT = os.environ.get('DB_PORT', '5432')

def get_db_connection():
    """Establishes and returns a database connection."""
    conn = None
    try:
        conn = psycopg2.connect(
            host=DB_HOST,
            database=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD,
            port=DB_PORT
        )
        return conn
    except Exception as e:
        app.logger.error(f"Database connection failed: {e}")
        raise

@app.route('/query', methods=['POST'])
def dynamic_query():
    """
    API endpoint to perform dynamic database queries.
    Expects a JSON body with:
    {
        "table_name": "your_table",
        "column_names": ["col1", "col2"], // Optional, defaults to all columns (*)
        "filter_conditions": [             // Optional
            {"column": "age", "operator": ">", "value": 25},
            {"column": "city", "operator": "=", "value": "New York"},
            {"column": "status", "operator": "IN", "value": ["active", "pending"]},
            {"column": "email", "operator": "LIKE", "value": "%example.com"},
            {"column": "description", "operator": "IS NULL"}
        ]
    }
    """
    data = request.get_json()

    table_name = data.get('table_name')
    column_names = data.get('column_names', [])
    filter_conditions = data.get('filter_conditions', [])

    if not table_name:
        return jsonify({"error": "table_name is required"}), 400

    conn = None
    try:
        conn = get_db_connection()
        # Use RealDictCursor to fetch rows as dictionaries
        with conn.cursor(cursor_factory=RealDictCursor) as cur:
            query_parts = []
            params = []

            # 1. SELECT clause
            if column_names:
                # Safely quote column identifiers
                columns_sql = sql.SQL(', ').join(sql.Identifier(col) for col in column_names)
            else:
                columns_sql = sql.SQL('*') # Select all columns
            
            # Start building the query
            query_parts.append(sql.SQL('SELECT {} FROM {}').format(columns_sql, sql.Identifier(table_name)))

            # 2. WHERE clause
            if filter_conditions:
                where_clauses = []
                supported_operators = ['=', '!=', '<', '>', '<=', '>=', 'LIKE', 'ILIKE', 'IN', 'IS NULL', 'IS NOT NULL']

                for condition in filter_conditions:
                    col = condition.get('column')
                    op = condition.get('operator')
                    val = condition.get('value')

                    if not col or not op:
                        return jsonify({"error": "Invalid filter condition: column and operator are required"}), 400
                    
                    if op not in supported_operators:
                        return jsonify({"error": f"Unsupported operator: {op}"}), 400

                    # Handle NULL checks which don't use a value parameter
                    if op in ['IS NULL', 'IS NOT NULL']:
                        where_clauses.append(sql.SQL('{} {}').format(sql.Identifier(col), sql.SQL(op)))
                    # Handle IN operator
                    elif op == 'IN':
                        if not isinstance(val, list):
                            return jsonify({"error": "'IN' operator requires a list value"}), 400
                        where_clauses.append(sql.SQL('{} IN %s').format(sql.Identifier(col)))
                        params.append(tuple(val)) # psycopg2 expects a tuple for IN
                    # Handle all other operators that take a single value parameter
                    else:
                        if val is None:
                             return jsonify({"error": f"Value is required for operator '{op}'"}), 400
                        where_clauses.append(sql.SQL('{} {} %s').format(sql.Identifier(col), sql.SQL(op)))
                        params.append(val)

                if where_clauses:
                    query_parts.append(sql.SQL('WHERE {}').format(sql.SQL(' AND ').join(where_clauses)))
            
            # Combine all query parts into a single SQL object
            final_query = sql.SQL(' ').join(query_parts)
            
            app.logger.debug(f"Executing query: {final_query.as_string(conn)}")
            app.logger.debug(f"With parameters: {params}")

            cur.execute(final_query, params)
            results = cur.fetchall()

            return jsonify(results)

    except psycopg2.Error as e:
        app.logger.error(f"Database error: {e}")
        return jsonify({"error": f"Database error: {e}"}), 500
    except Exception as e:
        app.logger.error(f"An unexpected error occurred: {e}")
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500
    finally:
        if conn:
            conn.close()

